public abstract class BaseRepository<TEntity, TKey> : IBaseRepository<TEntity, TKey> where TEntity : class
{
    protected readonly DbContext _context;
    protected readonly DbSet<TEntity> _dbSet;

    protected BaseRepository(DbContext context)
    {
        _context = context;
        _dbSet = context.Set<TEntity>();
    }

    public virtual TEntity GetById(TKey id)
    {
        return _dbSet.Find(id);
    }

    public virtual TEntity GetByDynamicField(Expression<Func<TEntity, bool>> expression)
    {
        return _dbSet.FirstOrDefault(expression);
    }

    public virtual TEntity GetByDynamicField(Expression<Func<TEntity, bool>> expression, params object[] parameters)
    {
        return _dbSet.AsQueryable().Where(expression, parameters).FirstOrDefault();
    }

    public virtual IEnumerable<TEntity> GetAll()
    {
        return _dbSet.ToList();
    }

    public virtual IEnumerable<TEntity> GetByDynamicFieldList(Expression<Func<TEntity, bool>> expression)
    {
        return _dbSet.Where(expression).ToList();
    }

    public virtual void Add(TEntity entity)
    {
        _dbSet.Add(entity);
        _context.SaveChanges();
